"""Weight tiers for parcel shipping."""

TIER_LIMITS = [
    (1, 3.00),
    (5, 7.50),
    (20, 15.00),
]


def tier_price(weight_kg):
    for limit, price in TIER_LIMITS:
        if weight_kg < limit:
            return price
    raise ValueError("parcel too heavy: " + str(weight_kg))

